export function processPayment(amountCents: number, cardToken: string) {
  if (amountCents <= 0) throw new Error('invalid amount');
  return chargeCard(cardToken, amountCents);
}

function chargeCard(cardToken: string, amountCents: number) {
  return { ok: true, cardToken, amountCents };
}
